SELECT i.*, sav.save_nm AS save_nm, ste.site_nm AS site_nm, cd_sit.code_label AS target_type_cd_nm FROM pm_save_item i LEFT JOIN pm_save sav ON sav.save_id = i.save_id LEFT JOIN sy_site ste ON ste.site_id = i.site_id LEFT JOIN sy_code cd_sit ON cd_sit.code_grp = 'SAVE_ITEM_TARGET' AND cd_sit.code_value = i.target_type_cd
ORDER BY i.save_item_id ASC ORDER BY i.save_item_id DESC ORDER BY i.reg_date ASC ORDER BY i.reg_date DESC ORDER BY i.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

